script:
function setupForm({ doc, call, toast, $dialog }) {

    const actions = []

    // Cross-sell Lead button
    actions.push({
        label: "Create Cross Sell Lead",
        onClick: () => {
            $dialog({
                title: "Create Cross Sell Lead",
                fields: [
                    {
                        label: "Entity",
                        fieldname: "entity",
                        fieldtype: "Select",
                        options: ["Aionion Capital", "Aionion Insurance", "US Subscription"],
                        reqd: 1
                    },
                    {
                        label: "Product",
                        fieldname: "product",
                        fieldtype: "Select",
                        options: ["Account Opening", "Bonds", "Mutual Funds", "Insurance Sales", "Insurance Renewals", "US Subscription"],
                        reqd: 1
                    }
                ],
                actions: [{
                    label: "Create Lead",
                    variant: "solid",
                    onClick: (close, values) => {
                        if (!values || !values.entity || !values.product) {
                            toast.error("Please select Entity and Product")
                            return
                        }
                        call(
                            "aionion_custom.aionion_custom.controllers.customer.create_cross_sell_lead",
                            { customer_name: doc.name, entity: values.entity, product: values.product }
                        ).then((r) => {
                            close()
                            toast.success("Cross-sell lead created: " + r)
                        }).catch((e) => {
                            close()
                            toast.error(e.message || "Error creating lead")
                        })
                    }
                }]
            })
        }
    })

    // Assigned Products button
    actions.push({
        label: "View Products",
        onClick: () => {
            call(
                "aionion_custom.aionion_custom.controllers.customer.get_customer_products",
                { customer_name: doc.name }
            ).then((products) => {
                if (!products || products.length === 0) {
                    toast.success("No products found for this customer")
                    return
                }
                let html = "<table style='width:100%;border-collapse:collapse'>"
                html += "<tr style='background:#f5f5f5'><th style='padding:8px;border:1px solid #ddd'>Type</th><th style='padding:8px;border:1px solid #ddd'>Product</th><th style='padding:8px;border:1px solid #ddd'>Status</th><th style='padding:8px;border:1px solid #ddd'>Reference</th></tr>"
                products.forEach(p => {
                    html += "<tr>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + p.type + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.product || "") + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.status || "") + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.reference || p.record || "") + "</td>"
                    html += "</tr>"
                })
                html += "</table>"
                $dialog({
                    title: "Assigned Products (" + products.length + ")",
                    html: html,
                    actions: []
                })
            }).catch((e) => {
                toast.error(e.message || "Error fetching products")
            })
        }
    })

    return { actions }
}

function setupList() {
  return {
    actions: [
      {
        label: "Customers",
        onClick: () => {
          window.open("/app/customer", "_blank");
        },
      },
      {
        label: "Tasks",
        onClick: () => {
          window.open("/app/aionion-task", "_blank");
        },
      },
    ],
  };
}

function setupForm({ doc, call, toast, $dialog }) {

    const actions = []

    // Hide/show sections based on entity
    setTimeout(() => {
        const entity = doc.custom_entity
        const hideLabels = entity === "US Subscription"
            ? ["Insurance Details", "Bonds", "Mutual Funds", "Account Opening"]
            : entity === "Aionion Insurance"
            ? ["Bonds", "Mutual Funds", "Account Opening"]
            : entity === "Aionion Capital"
            ? ["Insurance Details"]
            : ["Insurance Details", "Bonds", "Mutual Funds", "Account Opening"]

        document.querySelectorAll(".section-header span").forEach(el => {
            if (hideLabels.includes(el.textContent?.trim())) {
                const sectionContainer = el.closest(".section-header")?.parentElement
                if (sectionContainer) sectionContainer.style.display = "none"
            }
        })
    }, 800)

    // ── INSURANCE ────────────────────────────────────────────
    if (doc.custom_entity === "Aionion Insurance") {

        if ((!doc.docstatus || doc.docstatus === 0) && !doc.custom_service_rm) {
            actions.push({
                label: "Assign Service RM",
                onClick: () => {
                    call("aionion_custom.aionion_custom.controllers.crm_lead.get_suggested_service_rm",
                        { lead_name: doc.name }
                    ).then((suggestion) => {
                        $dialog({
                            title: "Assign Service RM",
                            message: "Suggested: " + (suggestion.service_rm_name || "None") + " | " + (suggestion.reason || ""),
                            actions: [{
                                label: "Confirm & Assign",
                                variant: "solid",
                                onClick: (close) => {
                                    if (!suggestion.service_rm) { toast.error("No Service RM available"); close(); return }
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                        { lead_name: doc.name, service_rm: suggestion.service_rm }
                                    ).then(() => {
                                        close()
                                        toast.success("Service RM assigned: " + suggestion.service_rm_name)
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }).catch((e) => { toast.error(e.message || "Error") })
                }
            })
        }

        if (!doc.docstatus || doc.docstatus === 0) {
            actions.push({
                label: "Submit Lead",
                onClick: () => {
                    if (!doc.custom_policy_status) { toast.error("Please set Policy Status before submitting."); return }
                    if (doc.custom_policy_status === "Issued" && !doc.custom_policy_number) { toast.error("Policy Number is mandatory when Policy Status is Issued."); return }
                    $dialog({
                        title: "Submit Lead",
                        message: "Are you sure? Lead will be locked after submission.",
                        actions: [{
                            label: "Submit",
                            variant: "solid",
                            onClick: (close) => {
                                call("aionion_custom.aionion_custom.controllers.crm_lead.submit_insurance_lead",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("Lead submitted! MIS team will now verify.")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Something went wrong") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.docstatus === 1 && doc.custom_product !== "Insurance Renewals") {
            if (doc.custom_mis_status !== "Approved") {
                actions.push({
                    label: "Verify MIS",
                    onClick: () => {
                        $dialog({
                            title: "Verify MIS",
                            message: "Have you verified Policy No " + (doc.custom_policy_number || "N/A") + " in the insurer portal?",
                            actions: [{
                                label: "Verify",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.approve_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("MIS Verified!")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }

            if (doc.custom_mis_status !== "Rejected") {
                actions.push({
                    label: "Reject MIS",
                    onClick: () => {
                        $dialog({
                            title: "Reject MIS",
                            message: "Reject MIS for " + doc.lead_name + "? Lead will be unlocked.",
                            actions: [{
                                label: "Reject",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.reject_mis",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("MIS Rejected. Lead unlocked.")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
        }
    }

    // ── US SUBSCRIPTION ──────────────────────────────────────
    if (doc.custom_entity === "US Subscription") {

        // Show payment info for MIS on submitted leads
        if (doc.docstatus === 1) {
            call("aionion_custom.aionion_custom.controllers.crm_lead.get_product_data",
                { lead_name: doc.name, product: "US Subscription" }
            ).then((rec) => {
                if (!rec) return

                // Show as toast notification with key details
                const payStatus = rec.payment_status || "Pending"
                const color = payStatus === "Approved" ? "green" : payStatus === "Rejected" ? "red" : "orange"

                toast[color === "green" ? "success" : color === "red" ? "error" : "warning"](
                    `💳 Payment: ${payStatus} | Amount: ${rec.amount_paid_us_subs > 0 ? rec.amount_paid_us_subs : "Not filled"} | Email: ${rec.email_address || rec.client_email || "—"} | Start: ${rec.sub_start_date || rec.sub_start_month || "—"} | End: ${rec.sub_end_date || rec.sub_end_month || "—"}`
                )
            })
        }

        // Assign Service RM — for US Subscription
        if ((!doc.docstatus || doc.docstatus === 0) && !doc.custom_service_rm) {
            actions.push({
                label: "Assign Service RM",
                onClick: () => {
                    call("aionion_custom.aionion_custom.controllers.crm_lead.get_suggested_service_rm",
                        { lead_name: doc.name }
                    ).then((suggestion) => {
                        $dialog({
                            title: "Assign Service RM",
                            message: "Suggested: " + (suggestion.service_rm_name || "None") + " | " + (suggestion.reason || ""),
                            actions: [{
                                label: "Confirm & Assign",
                                variant: "solid",
                                onClick: (close) => {
                                    if (!suggestion.service_rm) {
                                        toast.error("No US Subscription RM available")
                                        close()
                                        return
                                    }
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                        { lead_name: doc.name, service_rm: suggestion.service_rm }
                                    ).then(() => {
                                        close()
                                        toast.success("Service RM assigned: " + suggestion.service_rm_name)
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => {
                                        close()
                                        toast.error(e.message || "Error assigning Service RM")
                                    })
                                }
                            }]
                        })
                    }).catch((e) => {
                        toast.error(e.message || "Error getting suggestion")
                    })
                }
            })
        }

        // US Subscription Details — frappe dialog
        actions.push({
            label: "US Subscription Details",
            onClick: () => {
                call("aionion_custom.aionion_custom.controllers.crm_lead.get_product_data",
                    { lead_name: doc.name, product: "US Subscription" }
                ).then((record) => {
                    if (record && record.name) {
                        window.location.href = "/app/us-subscription-record/" + record.name
                    } else {
                        // Auto-create with lead data then open
                        call("aionion_custom.aionion_custom.controllers.crm_lead.create_us_subscription_from_lead",
                            { lead_name: doc.name }
                        ).then((new_record) => {
                            window.location.href = "/app/us-subscription-record/" + new_record
                        }).catch((e) => {
                            toast.error(e.message || "Error creating record")
                        })
                    }
                })
            }
        })

        // Submit US Lead
        if (!doc.docstatus || doc.docstatus === 0) {
            actions.push({
                label: "Submit US Lead",
                onClick: () => {
                    const mandatory = {
                        "lead_name": "Client Name",
                        "mobile_no": "Contact Number",
                        "email": "Email",
                        "custom_country": "Country of Residence",
                        "custom_employee_status": "Employment Status",
                        "custom_client_indian_investments": "Indian Investments",
                        "custom_client_intended_investment_in_us_market": "Intended Investment",
                        "custom_aionion_client_code": "Aionion Client Code",
                        // "custom_sales_rm_code": "EMP Code", // auto-filled on save
                        // "custom_sales_rm_branch": "EMP Branch", // optional - depends on HRMS
                    }
                    const missing = Object.entries(mandatory)
                        .filter(([field]) => !doc[field])
                        .map(([, label]) => label)

                    if (missing.length) { toast.error("Missing: " + missing.join(", ")); return }

                    $dialog({
                        title: "Submit US Lead",
                        message: "Submit this lead for payment verification by MIS?",
                        actions: [{
                            label: "Submit",
                            variant: "solid",
                            onClick: (close) => {
                                call("aionion_custom.aionion_custom.controllers.crm_lead.submit_us_lead",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("US Lead submitted! MIS team will verify payment.")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Something went wrong") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.docstatus === 1) {
            if (doc.custom_mis_status !== "Approved") {
                actions.push({
                    label: "Verify Payment",
                    onClick: () => {
                        $dialog({
                            title: "Verify Payment",
                            message: "Confirm payment received for " + doc.lead_name + "?",
                            actions: [{
                                label: "Verify",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.verify_us_payment",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.success("Payment verified!")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }

            if (doc.custom_mis_status !== "Rejected") {
                actions.push({
                    label: "Reject Payment",
                    onClick: () => {
                        $dialog({
                            title: "Reject Payment",
                            message: "Reason for rejection?",
                            actions: [{
                                label: "Reject",
                                variant: "solid",
                                onClick: (close) => {
                                    call("aionion_custom.aionion_custom.controllers.crm_lead.reject_us_payment",
                                        { lead_name: doc.name }
                                    ).then(() => {
                                        close()
                                        toast.error("Payment rejected.")
                                        setTimeout(() => window.location.href = window.location.href, 1500)
                                    }).catch((e) => { close(); toast.error(e.message || "Error") })
                                }
                            }]
                        })
                    }
                })
            }
        }
    }

    return { actions }
}

function setupForm({ doc, call, toast, $dialog }) {
    if (doc.custom_entity !== "Aionion Insurance") return
    if (doc.docstatus !== 1) return
    if (doc.custom_product === "Insurance Renewals") return

    const actions = []

    if (doc.custom_mis_status !== "Approved") {
        actions.push({
            label: "Verify MIS",
            onClick: () => {
                $dialog({
                    title: "Verify MIS",
                    message: "Have you verified Policy No " + (doc.custom_policy_number || "N/A") + " in the insurer portal?",
                    actions: [{ label: "Verify", variant: "solid", onClick: (close) => {
                        call("aionion_custom.aionion_custom.controllers.crm_lead.approve_mis",
                            { lead_name: doc.name }
                        ).then(() => {
                            close()
                            toast.success("MIS Verified!")
                            setTimeout(() => window.location.href = window.location.href, 1500)
                        }).catch((e) => { close(); toast.error(e.message || "Error") })
                    }}]
                })
            }
        })
    }

    if (doc.custom_mis_status !== "Rejected") {
        actions.push({
            label: "Reject MIS",
            onClick: () => {
                $dialog({
                    title: "Reject MIS",
                    message: "Reject MIS for " + doc.lead_name + "? Lead will be unlocked for Service RM to refill.",
                    actions: [{ label: "Reject", variant: "solid", onClick: (close) => {
                        call("aionion_custom.aionion_custom.controllers.crm_lead.reject_mis",
                            { lead_name: doc.name }
                        ).then(() => {
                            close()
                            toast.success("MIS Rejected. Lead unlocked.")
                            setTimeout(() => window.location.href = window.location.href, 1500)
                        }).catch((e) => { close(); toast.error(e.message || "Error") })
                    }}]
                })
            }
        })
    }

    return { actions }
}

function setupList({ call, columns, filters, setFilters }) {
    // Get current user's team employees from server
    call("aionion_custom.aionion_custom.controllers.crm_lead.get_my_team_employees", {})
    .then((employees) => {
        if (!employees || employees.length === 0) return

        // Get user IDs for these employees
        call("aionion_custom.aionion_custom.controllers.crm_lead.get_user_ids_for_employees",
            { employee_names: employees }
        ).then((userIds) => {
            if (!userIds || userIds.length === 0) return

            // Set filter to show only leads owned by team members
            setFilters([
                { fieldname: "lead_owner", operator: "in", value: userIds }
            ])
        })
    })
}
